const today = new Date();
const dateStart = new Date(today);
const dateEnd = new Date(today);
dateEnd.setDate(dateEnd.getDate() + 14);

const allEntries = $input.all();
const weekEntries = [];

for (const entry of allEntries) {
  const props = entry.json.properties;
  const dateProp = props?.Date?.date;

  if (!dateProp || !dateProp.start) continue;

  const entryDate = new Date(dateProp.start);
  const mappedDate = new Date(today.getFullYear(), entryDate.getMonth(), entryDate.getDate());

  if (mappedDate >= dateStart && mappedDate <= dateEnd) {
    const name = props?.Name?.title?.map(t => t.plain_text).join('') || '';
    const types = props?.['Email Type']?.multi_select?.map(s => s.name) || [];

    weekEntries.push({
      name: name,
      date: mappedDate.toISOString().split('T')[0],
      types: types,
      pageId: entry.json.id
    });
  }
}

weekEntries.sort((a, b) => new Date(a.date) - new Date(b.date));

return weekEntries.map(entry => ({
  json: entry
}));

const clients = $input.all();

return clients.map(client => ({
  json: {
    id: client.json.id,
    firmenname: client.json.fields?.Firmenname || '',
    klaviyoKey: client.json.fields?.['Klaviyo API Key'] || '',
    website: client.json.fields?.Website || '',
    branche: client.json.fields?.Branche || '',
    tonalitaet: client.json.fields?.Tonalität || '',
    emailFrom: client.json.fields?.['E-Mail Rechnungen'] || 'hello@adsdrop.de'
  }
}));

// Get ALL items from the merge node
const allItems = $input.all();

// Topics have: name, date, types, pageId
// Clients have: id, firmenname, klaviyoKey, website, branche, tonalitaet, emailFrom

const topics = allItems
  .filter(item => item.json.name && item.json.date && !item.json.firmenname)
  .map(item => item.json);

const clients = allItems
  .filter(item => item.json.firmenname && item.json.klaviyoKey)
  .map(item => item.json);

// Debug output
console.log(`Found ${topics.length} topics and ${clients.length} clients`);

if (topics.length === 0 || clients.length === 0) {
  return [{
    json: {
      error: 'No topics or clients found',
      topicsCount: topics.length,
      clientsCount: clients.length,
      sampleItems: allItems.slice(0, 3).map(i => i.json)
    }
  }];
}

// Create all combinations
const combinations = [];

for (const client of clients) {
  for (const topic of topics) {
    combinations.push({
      json: {
        topic: topic,
        client: client
      }
    });
  }
}

console.log(`Created ${combinations.length} combinations`);

return combinations;

const item = $input.first().json;
const client = item.client;
const topic = item.topic;

if (!client.website) {
  return [{
    json: {
      client: client,
      topic: topic,
      websiteHtml: '',
      error: 'No website URL'
    }
  }];
}

try {
  const response = await $httpRequest({
    method: 'GET',
    url: client.website,
    timeout: 10000
  });

  return [{
    json: {
      client: client,
      topic: topic,
      websiteHtml: response.body || ''
    }
  }];
} catch (error) {
  return [{
    json: {
      client: client,
      topic: topic,
      websiteHtml: '',
      error: error.message
    }
  }];
}

const item = $input.first().json;
const client = item.client;
const topic = item.topic;
const websiteHtml = item.websiteHtml || '';
const html = websiteHtml.toLowerCase();

// Detect product categories
const productKeywords = {
  'Mode': ['kleidung', 'fashion', 'bekleidung', 'outfit', 'style', 'kleider', 'shirts'],
  'Beauty': ['kosmetik', 'beauty', 'pflege', 'haut', 'makeup', 'serum'],
  'Home': ['möbel', 'home', 'wohnen', 'einrichtung', 'deko', 'interior'],
  'Tech': ['technik', 'gadgets', 'elektronik', 'smart', 'digital'],
  'Food': ['food', 'essen', 'kulinarik', 'gourmet', 'snacks', 'kaffee'],
  'Sport': ['sport', 'fitness', 'training', 'workout', 'active'],
  'Jewelry': ['schmuck', 'jewelry', 'uhren', 'accessoires']
};

const detectedProducts = [];
for (const [category, keywords] of Object.entries(productKeywords)) {
  if (keywords.some(kw => html.includes(kw))) {
    detectedProducts.push(category);
  }
}

const products = detectedProducts.length > 0 ? detectedProducts : ['Produkte', 'Angebote'];

// Detect tone
const luxuryIndicators = ['luxus', 'premium', 'exklusiv', 'hochwertig', 'edel', 'elegant'];
const casualIndicators = ['mega', 'super', 'cool', 'easy', 'entspannt', 'lässig'];

const luxuryScore = luxuryIndicators.filter(ind => html.includes(ind)).length;
const casualScore = casualIndicators.filter(ind => html.includes(ind)).length;

let tone = 'standard';
if (luxuryScore > 2) tone = 'luxury';
else if (casualScore > 2) tone = 'casual';

// Extract USP
const uspKeywords = ['nachhaltig', 'bio', 'vegan', 'handmade', 'regional', 'fair', 'öko'];
const usp = uspKeywords.find(kw => html.includes(kw))?.title() || 'Qualität und Service';

// Generate dynamic texts
const productNames = products.slice(0, 2).map(p => p);

let greeting;
if (tone === 'luxury') {
  greeting = `Willkommen in der Welt von ${client.firmenname}`;
} else if (tone === 'casual') {
  greeting = 'Hey! Schön, dass du da bist';
} else {
  greeting = `Hallo von ${client.firmenname}`;
}

// Add subject here for downstream nodes
const subject = `${topic.name} | ${client.firmenname}`;

return [{
  json: {
    client: client,
    topic: topic,
    subject: subject,
    analysis: {
      products: productNames,
      tone: tone,
      usp: usp,
      greeting: greeting,
      hook: productNames.length > 0 ? `Unsere ${productNames[0]} überzeugen durch ${usp}.` : 'Top-Qualität für dich.',
      previewText: productNames.length > 0 ? `Neue ${productNames[0]} entdecken` : 'Neues entdecken',
      context: `Bei uns findest du ${productNames.join(', ')} mit ${usp}.`,
      guarantee: html.includes('versand') ? 'Kostenloser Versand ab 50€' : '30 Tage Rückgabe'
    }
  }
}];

const item = $input.first().json;
const client = item.client;

try {
  const response = await $httpRequest({
    method: 'GET',
    url: 'https://a.klaviyo.com/api/lists',
    headers: {
      'Authorization': `Klaviyo-API-Key ${client.klaviyoKey}`,
      'revision': '2024-10-15'
    }
  });

  const lists = response.body?.data || [];
  let targetList = lists[0]?.id;

  for (const list of lists) {
    const name = list.attributes?.name?.toLowerCase() || '';
    if (name.includes('newsletter') || name.includes('main') || name.includes('all')) {
      targetList = list.id;
      break;
    }
  }

  return [{
    json: {
      ...item,
      targetList: targetList,
      lists: lists
    }
  }];
} catch (error) {
  return [{
    json: {
      ...item,
      targetList: null,
      error: error.message
    }
  }];
}

const item = $input.first().json;
const client = item.client;
const topic = item.topic;
const analysis = item.analysis;
const subject = item.subject;
const targetList = item.targetList;

// Calculate send date
const topicDate = topic.date;
const today = new Date();
let sendDate;

if (topicDate) {
  const topicDt = new Date(topicDate);
  if (topicDt < today) {
    sendDate = new Date(topicDt);
    sendDate.setDate(sendDate.getDate() + 7);
  } else {
    sendDate = topicDt;
  }
} else {
  sendDate = new Date(today);
  sendDate.setDate(sendDate.getDate() + 1);
}

const sendDatetime = sendDate.toISOString().split('T')[0] + 'T09:00:00.000Z';

const campaignData = {
  data: {
    type: 'campaign',
    attributes: {
      name: subject,
      audiences: {
        included: targetList ? [targetList] : []
      },
      send_strategy: {
        method: 'static',
        options_static: {
          datetime: sendDatetime
        }
      },
      'campaign-messages': {
        data: [
          {
            type: 'campaign-message',
            attributes: {
              channel: 'email',
              label: subject.slice(0, 50),
              content: {
                subject: subject,
                preview_text: analysis.previewText
              }
            }
          }
        ]
      }
    }
  }
};

try {
  const response = await $httpRequest({
    method: 'POST',
    url: 'https://a.klaviyo.com/api/campaigns',
    headers: {
      'Authorization': `Klaviyo-API-Key ${client.klaviyoKey}`,
      'revision': '2024-10-15',
      'Content-Type': 'application/json'
    },
    body: campaignData
  });

  return [{
    json: {
      client: client,
      topic: topic,
      subject: subject,
      campaignId: response.body?.data?.id,
      status: 'Created',
      sendDatetime: sendDatetime
    }
  }];
} catch (error) {
  return [{
    json: {
      client: client,
      topic: topic,
      subject: subject,
      campaignId: null,
      status: 'Failed',
      error: error.message
    }
  }];
}

const results = $input.all();
const successful = results.filter(r => r.json.campaignId).length;
const failed = results.length - successful;

const campaigns = results.map(r => ({
  client: r.json.client?.firmenname || 'Unknown',
  topic: r.json.topic?.name || 'Unknown',
  subject: r.json.subject,
  campaignId: r.json.campaignId,
  status: r.json.status
}));

const clientSummary = {};
for (const camp of campaigns) {
  if (!clientSummary[camp.client]) {
    clientSummary[camp.client] = 0;
  }
  if (camp.campaignId) {
    clientSummary[camp.client]++;
  }
}

return [{
  json: {
    successful: successful,
    failed: failed,
    total: results.length,
    campaigns: campaigns,
    clientSummary: clientSummary,
    week: new Date().toISOString().split('T')[0]
  }
}];

